1	use quote::{quote, ToTokens};
2	use rust_i18n_support::{
3	    MinifyKey, DEFAULT_MINIFY_KEY_LEN, DEFAULT_MINIFY_KEY_PREFIX, DEFAULT_MINIFY_KEY_THRESH,
4	};
5	use syn::{parse::discouraged::Speculative, token::Brace, Expr, Ident, LitStr, Token};
6	
7	#[derive(Clone, Debug, Default)]
8	pub enum Value {
9	    #[default]
10	    Empty,
11	    Expr(Expr),
12	    Ident(Ident),
13	}
14	
15	impl Value {
16	    fn is_expr_lit_str(&self) -> bool {
17	        if let Self::Expr(Expr::Lit(expr_lit)) = self {
18	            if let syn::Lit::Str(_) = &expr_lit.lit {
19	                return true;
20	            }
21	        }
22	        false
23	    }
24	
25	    fn is_expr_tuple(&self) -> bool {
26	        if let Self::Expr(Expr::Tuple(_)) = self {
27	            return true;
28	        }
29	        false
30	    }
31	
32	    fn to_string(&self) -> Option<String> {
33	        if let Self::Expr(Expr::Lit(expr_lit)) = self {
34	            if let syn::Lit::Str(lit_str) = &expr_lit.lit {
35	                return Some(lit_str.value());
36	            }
37	        }
38	        None
39	    }
40	
41	    fn to_tupled_token_streams(
42	        &self,
43	    ) -> syn::parse::Result<(proc_macro2::TokenStream, proc_macro2::TokenStream)> {
44	        if let Self::Expr(Expr::Tuple(expr_tuple)) = self {
45	            if expr_tuple.elems.len() == 2 {
46	                let first = expr_tuple.elems.first().map(|v| quote! { #v }).unwrap();
47	                let last = expr_tuple.elems.last().map(|v| quote! { #v }).unwrap();
48	                return Ok((first, last));
49	            }
50	        }
51	        Err(syn::Error::new_spanned(
52	            self,
53	            "Expected a tuple with two elements",
54	        ))
55	    }
56	}
57	
58	impl From<Expr> for Value {
59	    fn from(expr: Expr) -> Self {
60	        Self::Expr(expr)
61	    }
62	}
63	
64	impl From<Ident> for Value {
65	    fn from(ident: Ident) -> Self {
66	        Self::Ident(ident)
67	    }
68	}
69	
70	impl quote::ToTokens for Value {
71	    fn to_tokens(&self, tokens: &mut proc_macro2::TokenStream) {
72	        match self {
73	            Self::Empty => {}
74	            Self::Expr(expr) => match expr {
75	                Expr::Path(path) => quote! { &#path }.to_tokens(tokens),
76	                expr => expr.to_tokens(tokens),
77	            },
78	            Self::Ident(ident) => quote! { &#ident }.to_tokens(tokens),
79	        }
80	    }
81	}
82	
83	impl syn::parse::Parse for Value {
84	    fn parse(input: syn::parse::ParseStream) -> syn::parse::Result<Self> {
85	        let fork = input.fork();
86	        if let Ok(expr) = fork.parse::<Expr>() {
87	            input.advance_to(&fork);
88	            return Ok(expr.into());
89	        }
90	        let fork = input.fork();
91	        if let Ok(expr) = fork.parse::<Ident>() {
92	            input.advance_to(&fork);
93	            return Ok(expr.into());
94	        }
95	        Err(input.error("Expected a expression or an identifier"))
96	    }
97	}
98	
99	#[derive(Clone, Default)]
100	pub struct Argument {
101	    pub name: String,
102	    pub value: Value,
103	    pub specifiers: Option<String>,
104	}
105	
106	impl Argument {
107	    #[allow(dead_code)]
108	    pub fn value_string(&self) -> String {
109	        match &self.value {
110	            Value::Expr(Expr::Lit(expr_lit)) => match &expr_lit.lit {
111	                syn::Lit::Str(lit_str) => lit_str.value(),
112	                _ => self.value.to_token_stream().to_string(),
113	            },
114	            _ => self.value.to_token_stream().to_string(),
115	        }
116	    }
117	
118	    fn try_ident(input: syn::parse::ParseStream) -> syn::parse::Result<String> {
119	        let fork = input.fork();
120	        let ident = fork.parse::<Ident>()?;
121	        input.advance_to(&fork);
122	        Ok(ident.to_string())
123	    }
124	
125	    fn try_literal(input: syn::parse::ParseStream) -> syn::parse::Result<String> {
126	        let fork = input.fork();
127	        let lit = fork.parse::<LitStr>()?;
128	        input.advance_to(&fork);
129	        Ok(lit.value())
130	    }
131	}
132	
133	impl syn::parse::Parse for Argument {
134	    fn parse(input: syn::parse::ParseStream) -> syn::parse::Result<Self> {
135	        // Ignore leading commas.
136	        while input.peek(Token![,]) {
137	            let _ = input.parse::<Token![,]>()?;
138	        }
139	        // Parse the argument name.
140	        let name = Self::try_ident(input)
141	            .or_else(|_| Self::try_literal(input))
142	            .map_err(|_| input.error("Expected a `string` literal or an identifier"))?;
143	        // Parse the separator between the name and the value.
144	        if input.peek(Token![=>]) {
145	            let _ = input.parse::<Token![=>]>()?;
146	        } else if input.peek(Token![=]) {
147	            let _ = input.parse::<Token![=]>()?;
148	        } else {
149	            return Err(input.error("Expected `=>` or `=`"));
150	        }
151	        // Parse the argument value.
152	        let value = input.parse()?;
153	        // Parse the specifiers [optinal].
154	        let specifiers = if input.peek(Token![:]) {
155	            let _ = input.parse::<Token![:]>()?;
156	            if input.peek(Brace) {
157	                let content;
158	                let _ = syn::braced!(content in input);
159	                let mut specifiers = String::new();
160	                while let Ok(s) = content.parse::<proc_macro2::TokenTree>() {
161	                    specifiers.push_str(&s.to_string());
162	                }
163	                Some(specifiers)
164	            } else {
165	                None
166	            }
167	        } else {
168	            None
169	        };
170	        Ok(Self {
171	            name,
172	            value,
173	            specifiers,
174	        })
175	    }
176	}
177	
178	#[derive(Default)]
179	pub struct Arguments {
180	    pub args: Vec<Argument>,
181	}
182	
183	impl Arguments {
184	    pub fn is_empty(&self) -> bool {
185	        self.args.is_empty()
186	    }
187	
188	    pub fn iter(&self) -> impl Iterator<Item = &Argument> {
189	        self.args.iter()
190	    }
191	
192	    pub fn keys(&self) -> Vec<String> {
193	        self.args.iter().map(|arg| arg.name.clone()).collect()
194	    }
195	
196	    #[allow(dead_code)]
197	    pub fn values(&self) -> Vec<Value> {
198	        self.args.iter().map(|arg| arg.value.clone()).collect()
199	    }
200	}
201	
202	impl AsRef<Vec<Argument>> for Arguments {
203	    fn as_ref(&self) -> &Vec<Argument> {
204	        &self.args
205	    }
206	}
207	
208	impl AsMut<Vec<Argument>> for Arguments {
209	    fn as_mut(&mut self) -> &mut Vec<Argument> {
210	        &mut self.args
211	    }
212	}
213	
214	impl syn::parse::Parse for Arguments {
215	    fn parse(input: syn::parse::ParseStream) -> syn::parse::Result<Self> {
216	        let args = input
217	            .parse_terminated(Argument::parse, Token![,])?
218	            .into_iter()
219	            .collect();
220	        Ok(Self { args })
221	    }
222	}
223	
224	#[derive(Default)]
225	pub struct Messsage {
226	    #[allow(dead_code)]
227	    key: proc_macro2::TokenStream,
228	    val: Value,
229	}
230	
231	impl Messsage {
232	    fn try_exp(input: syn::parse::ParseStream) -> syn::parse::Result<Self> {
233	        let fork = input.fork();
234	        let expr = fork.parse::<Expr>()?;
235	        input.advance_to(&fork);
236	
237	        Ok(Self {
238	            key: Default::default(),
239	            val: Value::Expr(expr),
240	        })
241	    }
